// Alert triggers when the number of idle workers falls below the threshold.
// Low idle workers indicate the server is approaching capacity and may not handle new requests efficiently.
// The alert is grouped by host name.
// You can adjust the threshold value by modifying the idle_workers in the WHERE clause (default: < 5).
FROM metrics-apachereceiver.otel-*
| WHERE attributes.state == "idle"
| STATS idle_workers = AVG(metrics.apache.workers) BY resource.attributes.host.name
| WHERE idle_workers IS NOT NULL AND idle_workers < 5
| EVAL idle_workers = ROUND(idle_workers, 2)
| KEEP resource.attributes.host.name, idle_workers
| SORT idle_workers ASC
